import React, { useState, useRef } from 'react';

const ImageCompressor: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [result, setResult] = useState<{ originalSize: number; compressedSize: number } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setResult(null);
      setProgress(0);
    }
  };

  const handleCompress = () => {
    if (!selectedFile) return;

    setIsProcessing(true);
    setProgress(0);

    // Simulate compression progress
    const interval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsProcessing(false);
          setResult({
            originalSize: selectedFile.size,
            compressedSize: Math.floor(selectedFile.size * 0.42), // Mock 58% reduction
          });
          return 100;
        }
        return prev + 5;
      });
    }, 100);
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const clear = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setResult(null);
    setProgress(0);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="w-full max-w-2xl mx-auto bg-white dark:bg-slate-800 rounded-3xl shadow-xl p-8 border border-slate-100 dark:border-slate-700">
      <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-6 flex items-center">
        <i className="fa-solid fa-compress text-primary-500 mr-2"></i> Image Compressor
      </h3>

      {!selectedFile ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-2xl p-12 text-center cursor-pointer hover:border-primary-400 hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-all"
        >
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleFileChange} 
          />
          <div className="w-16 h-16 bg-primary-50 dark:bg-primary-900/20 rounded-full flex items-center justify-center mx-auto mb-4">
            <i className="fa-solid fa-cloud-arrow-up text-primary-500 text-2xl"></i>
          </div>
          <p className="text-slate-700 dark:text-slate-300 font-medium mb-1">Click to upload or drag and drop</p>
          <p className="text-slate-400 text-sm">PNG, JPG, WEBP up to 10MB</p>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="relative group">
            <img 
              src={previewUrl!} 
              alt="Preview" 
              className="w-full h-64 object-contain bg-slate-50 dark:bg-slate-900 rounded-2xl" 
            />
            <button 
              onClick={clear}
              className="absolute top-4 right-4 w-8 h-8 bg-white/80 dark:bg-slate-800/80 rounded-full flex items-center justify-center text-red-500 hover:scale-110 transition-transform shadow-sm"
            >
              <i className="fa-solid fa-trash-can"></i>
            </button>
          </div>

          <div className="flex justify-between items-center">
            <div>
              <p className="text-sm font-medium text-slate-800 dark:text-white truncate max-w-[200px]">{selectedFile.name}</p>
              <p className="text-xs text-slate-500">{formatSize(selectedFile.size)}</p>
            </div>

            {!result && !isProcessing && (
              <button 
                onClick={handleCompress}
                className="bg-primary-600 hover:bg-primary-700 text-white font-bold py-2 px-6 rounded-xl shadow-lg shadow-primary-500/20 transition-all active:scale-95"
              >
                Compress Image
              </button>
            )}
          </div>

          {isProcessing && (
            <div className="space-y-2">
              <div className="h-2 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-primary-500 transition-all duration-300" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
              <p className="text-xs text-center text-slate-500">Processing... {progress}%</p>
            </div>
          )}

          {result && (
            <div className="bg-green-50 dark:bg-green-900/10 border border-green-100 dark:border-green-900/30 rounded-2xl p-6">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center text-green-700 dark:text-green-400 font-bold">
                  <i className="fa-solid fa-circle-check mr-2"></i> Compression Successful!
                </div>
                <div className="text-xs font-bold px-2 py-1 bg-green-200 dark:bg-green-900 text-green-700 dark:text-green-300 rounded-lg">
                  -58% Savings
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4 mb-6">
                <div className="text-center p-3 bg-white dark:bg-slate-800 rounded-xl">
                  <p className="text-[10px] uppercase text-slate-400 font-bold mb-1">Before</p>
                  <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{formatSize(result.originalSize)}</p>
                </div>
                <div className="text-center p-3 bg-white dark:bg-slate-800 rounded-xl">
                  <p className="text-[10px] uppercase text-slate-400 font-bold mb-1">After</p>
                  <p className="text-sm font-bold text-primary-600">{formatSize(result.compressedSize)}</p>
                </div>
              </div>
              <a 
                href={previewUrl!} 
                download={`compressed_${selectedFile.name}`}
                className="block w-full text-center bg-primary-600 hover:bg-primary-700 text-white font-bold py-3 rounded-xl transition-all shadow-md active:scale-95"
              >
                Download Compressed Image
              </a>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default ImageCompressor;

import React, { useState, useRef } from 'react';

const ImageEnhancer: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [isDone, setIsDone] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setIsDone(false);
      setProgress(0);
    }
  };

  const handleEnhance = () => {
    if (!selectedFile) return;

    setIsProcessing(true);
    setProgress(0);

    // Simulate AI processing
    const interval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsProcessing(false);
          setIsDone(true);
          return 100;
        }
        return prev + 4;
      });
    }, 120);
  };

  const clear = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setIsDone(false);
    setProgress(0);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="w-full max-w-2xl mx-auto bg-white dark:bg-slate-800 rounded-3xl shadow-xl p-8 border border-slate-100 dark:border-slate-700">
      <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-6 flex items-center">
        <i className="fa-solid fa-sparkles text-amber-500 mr-2"></i> AI Image Enhancer
      </h3>

      {!selectedFile ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-2xl p-12 text-center cursor-pointer hover:border-amber-400 hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-all"
        >
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleFileChange} 
          />
          <div className="w-16 h-16 bg-amber-50 dark:bg-amber-900/20 rounded-full flex items-center justify-center mx-auto mb-4">
            <i className="fa-solid fa-wand-magic-sparkles text-amber-500 text-2xl"></i>
          </div>
          <p className="text-slate-700 dark:text-slate-300 font-medium mb-1">Upload blurry or low-res photos</p>
          <p className="text-slate-400 text-sm">PNG, JPG, WEBP up to 8MB</p>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="relative group overflow-hidden rounded-2xl bg-slate-50 dark:bg-slate-900">
             <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none">
                {isProcessing && (
                   <div className="w-24 h-24 border-4 border-amber-500/30 border-t-amber-500 rounded-full animate-spin"></div>
                )}
             </div>
            <img 
              src={previewUrl!} 
              alt="Preview" 
              className={`w-full h-64 object-contain transition-all duration-1000 ${isDone ? 'scale-105 saturate-110 brightness-110 contrast-110' : isProcessing ? 'blur-md grayscale' : ''}`} 
            />
             {isDone && (
                <div className="absolute top-0 left-0 w-full h-full pointer-events-none overflow-hidden">
                   <div className="absolute top-0 w-1 h-full bg-white/50 animate-[scan_2s_linear_infinite]"></div>
                </div>
             )}
            <button 
              onClick={clear}
              className="absolute top-4 right-4 z-20 w-8 h-8 bg-white/80 dark:bg-slate-800/80 rounded-full flex items-center justify-center text-red-500 hover:scale-110 transition-transform shadow-sm"
            >
              <i className="fa-solid fa-trash-can"></i>
            </button>
          </div>

          <div className="flex justify-between items-center">
            <div>
              <p className="text-sm font-medium text-slate-800 dark:text-white truncate max-w-[200px]">{selectedFile.name}</p>
              <p className="text-xs text-slate-500 uppercase tracking-tight">AI Enhancement Ready</p>
            </div>

            {!isDone && !isProcessing && (
              <button 
                onClick={handleEnhance}
                className="bg-amber-500 hover:bg-amber-600 text-white font-bold py-2 px-6 rounded-xl shadow-lg shadow-amber-500/20 transition-all active:scale-95"
              >
                Enhance Image
              </button>
            )}
          </div>

          {isProcessing && (
            <div className="space-y-2">
              <div className="h-2 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-amber-500 transition-all duration-300" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
              <p className="text-xs text-center text-slate-500 italic">Sharpening edges and restoring detail... {progress}%</p>
            </div>
          )}

          {isDone && (
            <div className="bg-amber-50 dark:bg-amber-900/10 border border-amber-100 dark:border-amber-900/30 rounded-2xl p-6">
              <div className="flex items-center text-amber-700 dark:text-amber-400 font-bold mb-4">
                <i className="fa-solid fa-magic mr-2"></i> AI Upscaling Complete!
              </div>
              <p className="text-sm text-slate-600 dark:text-slate-400 mb-6 leading-relaxed">
                We've enhanced the dynamic range, removed noise, and upscaled the resolution for a professional crisp finish.
              </p>
              <a 
                href={previewUrl!} 
                download={`enhanced_${selectedFile.name}`}
                className="block w-full text-center bg-amber-500 hover:bg-amber-600 text-white font-bold py-3 rounded-xl transition-all shadow-md active:scale-95"
