import React, { useState, useRef } from 'react';

const ImageCompressor: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [quality, setQuality] = useState(60);
  const [result, setResult] = useState<{ originalSize: number; compressedSize: number; ratio: number } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setResult(null);
      setProgress(0);
    }
  };

  const handleCompress = () => {
    if (!selectedFile) return;

    setIsProcessing(true);
    setProgress(0);

    // Simulate compression progress
    const interval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsProcessing(false);
          // Calculate mock compression based on quality slider
          // Lower quality slider = more compression = smaller file
          const compressionFactor = (quality / 100) * 0.7; 
          const compressedSize = Math.floor(selectedFile.size * compressionFactor);
          setResult({
            originalSize: selectedFile.size,
            compressedSize: compressedSize,
            ratio: Math.floor((1 - (compressedSize / selectedFile.size)) * 100)
          });
          return 100;
        }
        return prev + 5;
      });
    }, 80);
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const clear = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setResult(null);
    setProgress(0);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="w-full max-w-2xl mx-auto bg-white dark:bg-slate-800 rounded-3xl shadow-xl p-8 border border-slate-100 dark:border-slate-700 transition-all">
      <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-6 flex items-center">
        <i className="fa-solid fa-compress text-primary-500 mr-3"></i> Image Compressor
      </h3>

      {!selectedFile ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-3xl p-12 text-center cursor-pointer hover:border-primary-400 hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-all group"
        >
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleFileChange} 
          />
          <div className="w-16 h-16 bg-primary-50 dark:bg-primary-900/20 rounded-2xl flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
            <i className="fa-solid fa-cloud-arrow-up text-primary-500 text-2xl"></i>
          </div>
          <p className="text-slate-700 dark:text-slate-300 font-bold mb-1">Click to upload or drag and drop</p>
          <p className="text-slate-400 text-sm">High-res PNG, JPG or WEBP</p>
        </div>
      ) : (
        <div className="space-y-8">
          <div className="relative group rounded-2xl overflow-hidden bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-700">
            <img 
              src={previewUrl!} 
              alt="Preview" 
              className="w-full h-72 object-contain p-4" 
            />
            <button 
              onClick={clear}
              className="absolute top-4 right-4 w-10 h-10 bg-white/90 dark:bg-slate-800/90 rounded-xl flex items-center justify-center text-red-500 hover:bg-red-50 transition-colors shadow-sm"
              title="Remove image"
            >
              <i className="fa-solid fa-trash-can"></i>
            </button>
          </div>

          <div className="bg-slate-50 dark:bg-slate-900/50 p-6 rounded-2xl border border-slate-100 dark:border-slate-800">
            <div className="flex justify-between items-center mb-4">
              <label className="text-sm font-black text-slate-700 dark:text-slate-300 flex items-center">
                <i className="fa-solid fa-sliders mr-2 text-primary-500"></i>
                Compression Quality
              </label>
              <span className="text-sm font-black text-primary-600 bg-primary-50 dark:bg-primary-900/30 px-3 py-1 rounded-lg">{quality}%</span>
            </div>
            <input 
              type="range" 
              min="10" 
              max="95" 
              value={quality} 
              onChange={(e) => setQuality(parseInt(e.target.value))}
              disabled={isProcessing || !!result}
              className="w-full h-2 bg-slate-200 dark:bg-slate-700 rounded-lg appearance-none cursor-pointer accent-primary-600 disabled:opacity-50"
            />
            <div className="flex justify-between mt-2 text-[10px] text-slate-400 font-bold uppercase tracking-wider">
              <span>Small File</span>
              <span>Balanced</span>
              <span>Best Quality</span>
            </div>
          </div>

          {!result && !isProcessing && (
            <button 
              onClick={handleCompress}
              className="w-full bg-primary-600 hover:bg-primary-700 text-white font-black py-4 rounded-2xl shadow-xl shadow-primary-500/20 transition-all active:scale-95 flex items-center justify-center space-x-2"
            >
              <i className="fa-solid fa-bolt-lightning"></i>
              <span>Compress {formatSize(selectedFile.size)} Image</span>
            </button>
          )}

          {isProcessing && (
            <div className="space-y-4">
              <div className="h-3 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-primary-500 transition-all duration-300" 
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
              <p className="text-sm font-bold text-center text-slate-500 animate-pulse">Optimizing pixel data... {progress}%</p>
            </div>
          )}

          {result && (
            <div className="bg-green-50 dark:bg-green-900/10 border border-green-100 dark:border-green-900/30 rounded-3xl p-8 animate-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between mb-8">
                <div className="flex items-center text-green-700 dark:text-green-400 font-black text-lg">
                  <div className="w-8 h-8 bg-green-500 rounded-full flex items-center justify-center text-white mr-3 shadow-lg shadow-green-500/20">
                    <i className="fa-solid fa-check text-xs"></i>
                  </div>
                  Ready for Download
                </div>
                <div className="text-sm font-black px-4 py-2 bg-green-500 text-white rounded-xl shadow-lg shadow-green-500/20">
                  -{result.ratio}% Smaller
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6 mb-8">
                <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-green-100 dark:border-green-900/20 shadow-sm">
                  <p className="text-[10px] uppercase text-slate-400 font-black mb-1">Original Size</p>
                  <p className="text-lg font-black text-slate-700 dark:text-slate-300">{formatSize(result.originalSize)}</p>
                </div>
                <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-primary-100 dark:border-primary-900/20 shadow-sm">
                  <p className="text-[10px] uppercase text-primary-400 font-black mb-1">Optimized Size</p>
                  <p className="text-lg font-black text-primary-600">{formatSize(result.compressedSize)}</p>
                </div>
              </div>

              <div className="flex gap-4">
                <button 
                  onClick={clear}
                  className="px-6 py-4 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-bold rounded-2xl border border-slate-200 dark:border-slate-700 hover:bg-slate-50 transition-colors"
                >
                  <i className="fa-solid fa-arrow-rotate-left"></i>
                </button>
                <a 
                  href={previewUrl!} 
                  download={`compressed_${selectedFile.name}`}
                  className="flex-grow text-center bg-primary-600 hover:bg-primary-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-primary-500/20 active:scale-95"
                >
                  Download Compressed Image
                </a>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

