const ImageEnhancer: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [intensity, setIntensity] = useState(50);
  const [isDone, setIsDone] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [showComparison, setShowComparison] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setIsDone(false);
      setProgress(0);
      setShowComparison(false);
      setIsSaved(false);
    }
  };

  const handleEnhance = () => {
    if (!selectedFile) return;

    setIsProcessing(true);
    setProgress(0);

    // Simulate AI processing - higher intensity takes slightly longer
    const speed = 100 + (intensity / 2);
    const interval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(interval);
          setIsProcessing(false);
          setIsDone(true);
          return 100;
        }
        return prev + 5;
      });
    }, speed);
  };

  const handleSaveToLibrary = () => {
    if (!selectedFile || !previewUrl) return;

    const savedImages = JSON.parse(localStorage.getItem('saved_images') || '[]');
    const newImage = {
      id: Date.now().toString(),
      name: selectedFile.name,
      url: previewUrl,
      type: 'enhanced',
      date: new Date().toLocaleDateString(),
      size: 'High Res'
    };

    localStorage.setItem('saved_images', JSON.stringify([...savedImages, newImage]));
    setIsSaved(true);
  };

  const clear = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setIsDone(false);
    setProgress(0);
    setShowComparison(false);
    setIsSaved(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
