import React, { useState, useRef, useMemo, useEffect } from 'react';
import { supabase } from '../lib/supabase';

const ImageCompressor: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [compressedBlob, setCompressedBlob] = useState<Blob | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [quality, setQuality] = useState(80);
  const [isSaved, setIsSaved] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [result, setResult] = useState<{ originalSize: number; compressedSize: number; ratio: number } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setIsLoggedIn(!!session);
    });
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setCompressedBlob(null);
      setResult(null);
      setProgress(0);
      setIsSaved(false);
    }
  };

  const compressImage = async () => {
    if (!selectedFile) return;
    setIsProcessing(true);
    setProgress(20);

    const img = new Image();
    img.src = URL.createObjectURL(selectedFile);

    img.onload = () => {
      setProgress(50);
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');

      canvas.width = img.width;
      canvas.height = img.height;
      ctx?.drawImage(img, 0, 0);

      setProgress(80);
      canvas.toBlob(
        (blob) => {
          if (blob) {
            setCompressedBlob(blob);
            setResult({
              originalSize: selectedFile.size,
              compressedSize: blob.size,
              ratio: Math.floor((1 - (blob.size / selectedFile.size)) * 100)
            });
          }
          setProgress(100);
          setIsProcessing(false);
        },
        'image/jpeg',
        quality / 100
      );
    };
  };

  const handleSaveToLibrary = async () => {
    if (!selectedFile || !compressedBlob || !result) return;
    setIsSaving(true);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("User not authenticated");

      // 1. Upload to Supabase Storage
      const fileExt = selectedFile.name.split('.').pop();
      const fileName = `${user.id}/${Date.now()}.${fileExt}`;
      const filePath = `compressed/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, compressedBlob);

      if (uploadError) throw uploadError;

      // 2. Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from('images')
        .getPublicUrl(filePath);

      // 3. Save reference in Database
      const { error: dbError } = await supabase.from('images').insert([{
        user_id: user.id,
        name: selectedFile.name,
        url: publicUrl, 
        type: 'compressed',
        date: new Date().toISOString(),
        size: formatSize(result.compressedSize)
      }]);

      if (dbError) throw dbError;
      setIsSaved(true);
    } catch (err: any) {
      console.error('Save failed:', err);
      alert('Failed to save to cloud library: ' + err.message);
    } finally {
      setIsSaving(false);
    }
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const clear = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setCompressedBlob(null);
    setResult(null);
    setProgress(0);
    setIsSaved(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const visualStyle = useMemo(() => {
