import React, { useState, useRef, useMemo, useEffect } from 'react';
import { supabase } from '../lib/supabase';

const ImageCompressor: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [compressedBlob, setCompressedBlob] = useState<Blob | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState(0);
  const [quality, setQuality] = useState(80);
  const [isSaved, setIsSaved] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [result, setResult] = useState<{ originalSize: number; compressedSize: number; ratio: number } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Initial check
    supabase.auth.getSession().then(({ data: { session } }) => {
      setIsLoggedIn(!!session);
    });

    // Listen for changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setIsLoggedIn(!!session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setCompressedBlob(null);
      setResult(null);
      setProgress(0);
      setIsSaved(false);
    }
  };

  const compressImage = async () => {
    if (!selectedFile) return;
    setIsProcessing(true);
    setProgress(20);

    const img = new Image();
    img.src = URL.createObjectURL(selectedFile);

    img.onload = () => {
      setProgress(50);
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');

      canvas.width = img.width;
      canvas.height = img.height;
      ctx?.drawImage(img, 0, 0);

      setProgress(80);
      canvas.toBlob(
        (blob) => {
          if (blob) {
            setCompressedBlob(blob);
            setResult({
              originalSize: selectedFile.size,
              compressedSize: blob.size,
              ratio: Math.floor((1 - (blob.size / selectedFile.size)) * 100)
            });
          }
          setProgress(100);
          setIsProcessing(false);
        },
        'image/jpeg',
        quality / 100
      );
    };
  };

  const handleSaveToLibrary = async () => {
    if (!selectedFile || !compressedBlob || !result) return;
    setIsSaving(true);

    try {
      // Re-verify session to get fresh user ID
      const { data: { session }, error: sessionError } = await supabase.auth.getSession();
      if (sessionError || !session?.user) {
        throw new Error("You must be logged in to save images to the cloud.");
      }

      const user = session.user;
      console.log('Attempting save for user:', user.id);

      // 1. Upload to Supabase Storage
      const fileExt = selectedFile.name.split('.').pop();
      const fileName = `${Date.now()}_${selectedFile.name.replace(/[^a-zA-Z0-9.]/g, '_')}`;
      const filePath = `${user.id}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, compressedBlob, {
          cacheControl: '3600',
          upsert: false
        });

      if (uploadError) {
        throw new Error(`Cloud Storage Error: ${uploadError.message}`);
      }

      // 2. Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from('images')
        .getPublicUrl(filePath);

      // 3. Save reference in Database
      const { error: dbError } = await supabase.from('images').insert([{
        user_id: user.id,
        name: selectedFile.name,
        url: publicUrl, 
        type: 'compressed',
        date: new Date().toISOString(),
        size: formatSize(result.compressedSize)
      }]);

      if (dbError) {
        // If DB fails, try to cleanup the storage file
        await supabase.storage.from('images').remove([filePath]);
        throw new Error(`Database Error: ${dbError.message}. Ensure you have run the RLS SQL fix.`);
      }

      setIsSaved(true);
    } catch (err: any) {
      console.error('Save failed:', err);
      alert(err.message || 'An unexpected error occurred while saving.');
    } finally {
      setIsSaving(false);
    }
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const clear = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setCompressedBlob(null);
    setResult(null);
    setProgress(0);
    setIsSaved(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const visualStyle = useMemo(() => {
    if (!selectedFile) return {};
    const blurValue = (100 - quality) / 25; 
    const contrastValue = 1 + (100 - quality) / 500;
