                  Enhancement Complete
                </div>
                <div className="text-sm font-black px-6 py-2.5 bg-green-500 text-white rounded-2xl shadow-xl shadow-green-500/30">
                  AI Processed
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6 mb-10">
