import ReviewCard from '../components/ReviewCard';
import ReviewForm from '../components/ReviewForm';
import { Feature, Review } from '../types';
import { supabase } from '../lib/supabase';

const Home: React.FC = () => {
  const [activeTool, setActiveTool] = useState<'none' | 'compress' | 'enhance'>('none');
  const [reviews, setReviews] = useState<Review[]>([]);
  const [searchParams] = useSearchParams();
  const toolRef = useRef<HTMLDivElement>(null);

  const curatedReviews: Review[] = [
    { id: 'c1', name: 'Sarah Jenkins', rating: 5, comment: 'LamaImage has completely replaced my expensive desktop tools for quick web exports. The compression is magic!', approved: true, created_at: '2026-03-24T10:00:00Z' },
    { id: 'c2', name: 'Mark Wu', rating: 5, comment: 'I needed a quick way to optimize assets for a client site. This tool saved me hours and the results were flawless.', approved: true, created_at: '2026-03-20T10:00:00Z' },
    { id: 'c3', name: 'Elena Rodriguez', rating: 5, comment: 'The AI enhancer actually works! I recovered a blurry shot that I thought was unusable. Amazing service.', approved: true, created_at: '2026-03-15T10:00:00Z' },
  ];

  const fetchApprovedReviews = async () => {
    const { data, error } = await supabase
      .from('reviews')
      .select('*')
      .eq('approved', true)
      .order('created_at', { ascending: false })
      .limit(6);

    if (data && data.length > 0) {
      setReviews(data as Review[]);
    } else {
      setReviews(curatedReviews);
    }
  };

  useEffect(() => {
    fetchApprovedReviews();

    // OPTIONAL: Subscribe to Realtime updates
    // This will refresh the list for everyone if an admin approves a review
    const channel = supabase
      .channel('public:reviews')
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'reviews' }, (payload) => {
        if (payload.new.approved === true) {
          fetchApprovedReviews();
        }
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  useEffect(() => {
    const toolParam = searchParams.get('tool');
    if (toolParam === 'compress' || toolParam === 'enhance') {
      setActiveTool(toolParam as 'compress' | 'enhance');
      setTimeout(() => {
        toolRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 300);
    }
  }, [searchParams]);

  const handleNewReview = (newReview: Review) => {
    // Optimistically add the new review to the top of the list
    // even though it's not "approved" yet, we show it to the current user
    setReviews(prev => [newReview, ...prev].slice(0, 6));

    // Smoothly scroll to the reviews section to show the newly added card
    const reviewsSection = document.getElementById('reviews-section');
    reviewsSection?.scrollIntoView({ behavior: 'smooth' });
  };

