        await supabase.storage.from('images').remove([filePath]);
        throw new Error(`Database save failed: ${dbError.message}`);
      }

      setIsSaved(true);
    } catch (err: any) {
      console.error('Save failed:', err);
      setError(err.message || 'An unexpected error occurred while saving.');
