import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { GoogleGenAI } from "@google/genai";

const ImageEnhancer: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [enhancedUrl, setEnhancedUrl] = useState<string | null>(null);
  const [enhancedBlob, setEnhancedBlob] = useState<Blob | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [intensity, setIntensity] = useState(75);
  const [isDone, setIsDone] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [hasProKey, setHasProKey] = useState(false);
  const [error, setError] = useState<React.ReactNode | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setIsLoggedIn(!!session);
    });

    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setHasProKey(hasKey);
      }
    };
    checkKey();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setIsLoggedIn(!!session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const handleSelectKey = async () => {
    try {
      if (window.aistudio?.openSelectKey) {
        await window.aistudio.openSelectKey();
        // Assume key selection was successful to avoid race conditions
        setHasProKey(true); 
        setError(null);
      } else {
        alert("API Key selection is only available in the AI Studio environment.");
      }
    } catch (err) {
      console.error("Failed to open key selector", err);
    }
  };

  const fileToBase64 = (file: File | Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  const getClosestAspectRatio = (width: number, height: number): "1:1" | "4:3" | "3:4" | "16:9" | "9:16" => {
    const ratio = width / height;
    if (ratio > 1.5) return "16:9";
    if (ratio > 1.2) return "4:3";
    if (ratio < 0.6) return "9:16";
    if (ratio < 0.8) return "3:4";
    return "1:1";
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setEnhancedUrl(null);
      setEnhancedBlob(null);
      setIsDone(false);
      setIsSaved(false);
      setError(null);
    }
  };

  const handleEnhance = async () => {
    if (!selectedFile) return;
    if (!hasProKey) {
      setError(<span>Please <button onClick={handleSelectKey} className="underline font-black">unlock Pro AI</button> first to access 4K enhancement.</span>);
      return;
    }

    setIsProcessing(true);
    setError(null);

    try {
      // Create fresh instance right before call to ensure latest API key is used
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const img = new Image();
      img.src = previewUrl!;
      await new Promise(r => img.onload = r);

      const targetAspectRatio = getClosestAspectRatio(img.width, img.height);
      const targetSize: "1K" | "2K" | "4K" = intensity > 70 ? "4K" : intensity > 35 ? "2K" : "1K";

      // Fix: Convert the source file to base64 before making the Gemini API request
      const base64Data = await fileToBase64(selectedFile);

      const prompt = `You are a world-class AI Image Restoration specialist. 
      TASK: Enhance this input image into a professional 4K masterpiece.
      1. Reconstruct all missing textures including skin pores, fabric weaves, and environmental details.
      2. REMOVE all JPEG artifacts, blur, and sensor noise.
      3. UPSCALING: Use high-density pixel reconstruction to fill the ${targetSize} frame.
      4. Ensure the output has professional color grading and ultra-sharp edges.
      Intended Output Complexity: 10/10. Restore it to look like it was taken with a high-end 80MP camera.
      Intensity Level: ${intensity}% sharpness.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: selectedFile.type } },
            { text: prompt }
          ]
        },
        config: {
          imageConfig: {
            aspectRatio: targetAspectRatio,
            imageSize: targetSize
          }
        }
      });

      let foundImage = false;
      const candidate = response.candidates?.[0];
      if (candidate?.content?.parts) {
        // Iterate through parts to find the image response as per guideline
        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            const base64Res = part.inlineData.data;
            const enhancedDataUrl = `data:${part.inlineData.mimeType};base64,${base64Res}`;

            const res = await fetch(enhancedDataUrl);
            const blob = await res.blob();

            setEnhancedBlob(blob);
            setEnhancedUrl(enhancedDataUrl);
            setIsDone(true);
            foundImage = true;
            break;
          }
        }
      }

      if (!foundImage) {
        throw new Error("Pro AI did not return an image part. Ensure your project is correctly configured.");
      }
    } catch (err: any) {
      console.error('Enhancement failed:', err);
      const msg = err.message || "";

      if (msg.includes("403") || msg.toLowerCase().includes("permission") || msg.toLowerCase().includes("caller does not have permission")) {
        setHasProKey(false);
        setError(
          <div className="space-y-2">
            <p className="font-black text-red-600">Access Denied (403)</p>
            <p className="text-[11px] leading-relaxed">
              Your selected API key does not have permission for the Pro model. 
              <strong> You must select a key from a Paid GCP Project</strong> with billing enabled.
            </p>
            <div className="pt-2 flex gap-3">
              <button onClick={handleSelectKey} className="px-4 py-1.5 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase">Re-select Key</button>
              <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener" className="px-4 py-1.5 bg-slate-100 dark:bg-slate-700 rounded-lg text-[10px] font-black uppercase">Billing Guide</a>
            </div>
          </div>
        );
      } else if (msg.includes("Requested entity was not found")) {
        setHasProKey(false);
        setError("Model not found. Please re-select your Pro API key.");
      } else {
        setError(msg || "Pro Enhancement failed. Ensure billing is enabled in your GCP project.");
      }
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSaveToLibrary = async () => {
    const dataToSave = enhancedBlob || selectedFile;
    if (!dataToSave || !selectedFile) return;

    setIsSaving(true);
    try {
      const { data: { session }, error: sessionError } = await supabase.auth.getSession();
      if (sessionError || !session?.user) {
        throw new Error("You must be logged in to save images.");
      }

      const user = session.user;
      const cleanFileName = selectedFile.name.replace(/[^a-zA-Z0-9.]/g, '_');
      const fileName = `${Date.now()}_pro_hd_${cleanFileName}`;
      const filePath = `${user.id}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, dataToSave, {
          cacheControl: '3600',
          upsert: false,
          contentType: (dataToSave as any).type || selectedFile.type
        });

      if (uploadError) throw new Error(`Upload failed: ${uploadError.message}`);

      const { data: { publicUrl } } = supabase.storage
        .from('images')
        .getPublicUrl(filePath);

      const { error: dbError } = await supabase.from('images').insert([{
        user_id: user.id,
        name: selectedFile.name,
        url: publicUrl,
        type: 'enhanced',
        date: new Date().toISOString(),
        size: intensity > 70 ? '4K Ultra-HD' : intensity > 35 ? '2K HD+' : 'HD Restored'
      }]);

      if (dbError) {
        await supabase.storage.from('images').remove([filePath]);
        throw new Error(`Database save failed: ${dbError.message}`);
      }

      setIsSaved(true);
    } catch (err: any) {
      console.error('Save failed:', err);
      setError(err.message || 'An unexpected error occurred while saving.');
    } finally {
      setIsSaving(false);
    }
  };

  const clear = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setEnhancedUrl(null);
    setEnhancedBlob(null);
    setIsDone(false);
    setIsSaved(false);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="w-full max-w-2xl mx-auto bg-white dark:bg-slate-800 rounded-[40px] shadow-2xl p-8 border border-slate-100 dark:border-slate-700 transition-all">
      <div className="flex items-center justify-between mb-8">
        <h3 className="text-xl font-black text-slate-800 dark:text-white flex items-center">
          <div className="w-8 h-8 bg-amber-100 dark:bg-amber-900/30 rounded-lg flex items-center justify-center mr-3 text-amber-600">
             <i className="fa-solid fa-sparkles text-sm"></i>
          </div>
          4K Pro Enhancer
        </h3>
        {selectedFile && (
          <div className="flex items-center space-x-2">
            {!hasProKey && (
              <button 
                onClick={handleSelectKey}
                className="text-[10px] font-black uppercase tracking-widest text-white bg-primary-600 px-3 py-1.5 rounded-full hover:bg-primary-700 transition-all animate-pulse"
              >
                Unlock Pro (4K)
              </button>
            )}
            {hasProKey && (
              <span className="text-[10px] font-black uppercase tracking-widest text-green-500 bg-green-50 dark:bg-green-900/30 px-3 py-1.5 rounded-full border border-green-100 dark:border-green-800 flex items-center">
                <i className="fa-solid fa-crown mr-1.5"></i> Pro Active
              </span>
            )}
          </div>
        )}
      </div>

      {!selectedFile ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-[32px] p-16 text-center cursor-pointer hover:border-amber-400 hover:bg-amber-50/30 dark:hover:bg-amber-900/10 transition-all group relative overflow-hidden"
        >
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleFileChange} 
          />
          <div className="w-20 h-20 bg-amber-50 dark:bg-amber-900/20 rounded-3xl flex items-center justify-center mx-auto mb-6 group-hover:scale-110 group-hover:rotate-3 transition-transform duration-500">
            <i className="fa-solid fa-wand-magic-sparkles text-amber-500 text-3xl"></i>
          </div>
          <p className="text-xl text-slate-700 dark:text-slate-300 font-black mb-2">Enhance to 4K Ultra HD</p>
          <p className="text-slate-400 text-sm font-medium">Reconstruct lost details with Pro AI Models</p>
        </div>
      ) : (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          {error && (
            <div className="p-5 bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-900/30 rounded-2xl text-red-600 dark:text-red-400 text-xs font-bold flex items-start">
              <i className="fa-solid fa-circle-exclamation mr-3 mt-1 text-base"></i>
              <div className="flex-1">
                {error}
              </div>
            </div>
          )}

          <div className="relative group rounded-3xl overflow-hidden bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-700 aspect-video flex items-center justify-center">
            {isProcessing && (
               <div className="absolute inset-0 flex flex-col items-center justify-center z-30 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md">
                  <div className="w-20 h-20 border-8 border-amber-500/10 border-t-amber-500 rounded-full animate-spin mb-4"></div>
                  <p className="text-xs font-black text-amber-600 uppercase tracking-widest animate-pulse">Deep Pixel Reconstruction...</p>
               </div>
            )}

            <img 
              src={enhancedUrl || previewUrl!} 
              alt="Preview" 
              className={`max-w-full max-h-full object-contain p-4 transition-all duration-700 ${isDone ? 'scale-100' : 'opacity-80'}`} 
            />

            {isDone && (
              <div className="absolute top-0 left-0 w-full h-full pointer-events-none overflow-hidden z-20">
                <div className="absolute top-0 w-2 h-full bg-white/50 shadow-[0_0_20px_white] animate-[scan_2s_linear_infinite]"></div>
              </div>
            )}

            <button 
              onClick={clear}
              className="absolute top-4 right-4 z-40 w-11 h-11 bg-white dark:bg-slate-800 rounded-2xl flex items-center justify-center text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-all shadow-xl border border-slate-100 dark:border-slate-700 hover:scale-110 active:scale-90"
            >
              <i className="fa-solid fa-trash-can text-lg"></i>
            </button>

            <div className="absolute bottom-4 left-4 right-4 flex justify-between items-center pointer-events-none z-30">
               <div className="bg-white/80 dark:bg-slate-800/80 backdrop-blur-md px-4 py-2 rounded-xl border border-white/20 text-[10px] font-black text-amber-600 shadow-xl uppercase tracking-widest">
                  {isDone ? 'PRO HD SUCCESS' : `Target: ${intensity > 70 ? '4K UHD' : intensity > 35 ? '2K HD' : '1K'}`}
               </div>
               <div className="bg-amber-500 px-4 py-2 rounded-xl text-[10px] font-black text-white shadow-xl shadow-amber-500/30 uppercase tracking-widest">
                  {isDone ? 'OUTPUT ~4MB+' : 'AI PRO READY'}
               </div>
            </div>
          </div>

          <div className="bg-amber-50/50 dark:bg-amber-900/10 p-8 rounded-[32px] border border-amber-100/50 dark:border-amber-900/20 shadow-inner">
            <div className="flex justify-between items-center mb-6">
              <label className="text-sm font-black text-slate-700 dark:text-slate-300 flex items-center">
                <div className="w-2 h-2 rounded-full bg-amber-500 mr-2 animate-pulse"></div>
                Upscale Resolution (4K Target)
              </label>
              <span className="text-sm font-black text-amber-600 bg-white dark:bg-slate-800 px-4 py-1.5 rounded-xl border border-amber-100 dark:border-amber-900/30 shadow-sm">
                {intensity}% ({intensity > 70 ? '4K' : intensity > 35 ? '2K' : '1K'})
              </span>
            </div>
            <input 
              type="range" 
              min="0" 
              max="100" 
              value={intensity} 
              onChange={(e) => {
                setIntensity(parseInt(e.target.value));
                setIsDone(false);
              }}
              disabled={isProcessing}
              className="w-full h-3 bg-slate-200 dark:bg-slate-700 rounded-full appearance-none cursor-pointer accent-amber-500 transition-all"
            />
            <div className="flex justify-between mt-4 text-[11px] text-slate-400 font-black uppercase tracking-widest">
              <span>Standard</span>
              <span>2K HD</span>
              <span>4K Ultra</span>
            </div>
          </div>

          {!isDone && !isProcessing && (
            <div className="space-y-4">
              {!hasProKey ? (
                <button 
                  onClick={handleSelectKey}
                  className="w-full bg-primary-600 hover:bg-primary-700 text-white font-black py-5 rounded-[24px] shadow-2xl shadow-primary-500/30 transition-all hover:scale-[1.02] flex items-center justify-center space-x-3"
                >
                  <i className="fa-solid fa-key text-sm"></i>
                  <span>Unlock Pro 4K Enhancement</span>
                </button>
              ) : (
                <button 
                  onClick={handleEnhance}
                  className="group w-full bg-amber-500 hover:bg-amber-600 text-white font-black py-5 rounded-[24px] shadow-2xl shadow-amber-500/30 transition-all hover:scale-[1.02] flex items-center justify-center space-x-3 overflow-hidden relative"
                >
                  <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-700"></div>
                  <i className="fa-solid fa-wand-magic-sparkles text-sm group-hover:rotate-45 transition-transform duration-500"></i>
                  <span>Run Pro Detail Reconstruction</span>
                </button>
              )}
              <p className="text-[10px] text-center text-slate-400 font-bold uppercase tracking-widest">
                <i className="fa-solid fa-circle-info mr-1"></i> Pro Key requires a paid GCP project (ai.google.dev/gemini-api/docs/billing)
              </p>
            </div>
          )}

          {isDone && (
