    const isUltraRequest = intensity > 70 || (intensity > 35 && hasProKey);
    const targetModel = (isUltraRequest && hasProKey) ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
    const targetSize: "1K" | "2K" | "4K" = (intensity > 70 && hasProKey) ? "4K" : (intensity > 35 && hasProKey) ? "2K" : "1K";

    setIsProcessing(true);
    setError(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const img = new Image();
      img.src = previewUrl!;
      await new Promise(r => img.onload = r);

      const targetAspectRatio = getClosestAspectRatio(img.width, img.height);
      const base64Data = await fileToBase64(selectedFile);

      const prompt = `Task: Enhance and restore this image. 
