            <i className="fa-solid fa-crown mr-1.5"></i> 4K Pro Unlocked
          </span>
        ) : (
          <button 
            onClick={handleSelectKey}
            className="text-[10px] font-black uppercase tracking-widest text-white bg-slate-800 dark:bg-slate-700 px-3 py-1.5 rounded-full hover:bg-black transition-all"
          >
            Unlock 4K (Pro)
          </button>
        )}
      </div>

      {!selectedFile ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-[32px] p-16 text-center cursor-pointer hover:border-amber-400 hover:bg-amber-50/30 dark:hover:bg-amber-900/10 transition-all group"
        >
