      const prompt = `Task: Enhance and restore this image. 
      Details: Remove JPEG artifacts, noise, and blur. 
      Quality Target: ${targetSize}.
      Reconstruct textures (skin, fabric, environment) to look sharp and professional.
      Ensure high dynamic range and clear edges. Intensity: ${intensity}%.`;

      // gemini-2.5-flash-image doesn't support imageSize config, only AspectRatio
      const config: any = {
        imageConfig: {
          aspectRatio: targetAspectRatio
        }
      };

      if (targetModel === 'gemini-3-pro-image-preview') {
        config.imageConfig.imageSize = targetSize;
      }

      const response = await ai.models.generateContent({
        model: targetModel,
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: selectedFile.type } },
            { text: prompt }
          ]
        },
        config: config
      });

      let foundImage = false;
      const candidate = response.candidates?.[0];
      if (candidate?.content?.parts) {
        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            const base64Res = part.inlineData.data;
            const enhancedDataUrl = `data:${part.inlineData.mimeType};base64,${base64Res}`;
            const res = await fetch(enhancedDataUrl);
            const blob = await res.blob();

            setEnhancedBlob(blob);
            setEnhancedUrl(enhancedDataUrl);
            setIsDone(true);
            foundImage = true;
            break;
          }
        }
      }

      if (!foundImage) {
        throw new Error("AI completed the task but didn't return an image part. Please try again.");
      }
    } catch (err: any) {
      console.error('Enhancement failed:', err);
      const msg = err.message || "";

      // Specifically handle the 403 Permission Denied error
      if (msg.includes("403") || msg.toLowerCase().includes("permission") || msg.toLowerCase().includes("denied")) {
        setError(
          <div className="space-y-4">
            <div className="flex items-center text-red-600 dark:text-red-400 font-black uppercase tracking-widest text-[11px]">
              <i className="fa-solid fa-shield-halved mr-2"></i>
