                  <a href={enhancedUrl!} download="lama_restored_hd.png" className="flex-grow text-center bg-primary-600 text-white font-black py-5 rounded-[24px] shadow-xl hover:scale-[1.02] transition-all flex items-center justify-center space-x-2">
                    <i className="fa-solid fa-download"></i>
                    <span>Download {intensity > 35 ? 'HD Master' : 'Restored Image'}</span>
                  </a>
                </div>
                {isLoggedIn && (
                  <button onClick={handleSaveToLibrary} disabled={isSaved || isSaving} className={`w-full py-4 rounded-[20px] font-black text-sm transition-all flex items-center justify-center space-x-2 ${isSaved ? 'bg-green-100 text-green-600 border border-green-200' : 'bg-slate-800 text-white hover:bg-black shadow-lg'}`}>
                    {isSaving ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className={`fa-solid ${isSaved ? 'fa-check' : 'fa-cloud-arrow-up'}`}></i>}
                    <span>{isSaved ? 'Saved to Cloud Library' : isSaving ? 'Saving HD Assets...' : 'Save to My Library'}</span>
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

