  const handleEnhance = async () => {
    if (!selectedFile) return;

    setIsProcessing(true);
    setError(null);

    try {
      await checkAndSelectKey();

      // Fix: Create GoogleGenAI instance right before the call as per guidelines
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const img = new Image();
      img.src = previewUrl!;
      await new Promise(r => img.onload = r);

      const targetAspectRatio = getClosestAspectRatio(img.width, img.height);
      const base64Data = await fileToBase64(selectedFile);

      const prompt = `Task: Perform an Ultra-HD 4K Image Restoration. Intensity: ${intensity}%.`;

      // Fix: Upgrade to gemini-3-pro-image-preview for 4K quality tasks
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: selectedFile.type } },
            { text: prompt }
          ]
        },
        config: {
          imageConfig: { 
            aspectRatio: targetAspectRatio,
            imageSize: '4K' // Fix: Set imageSize to 4K for 4K restoration tasks
          }
        }
      });

      let foundImage = false;
      const candidate = response.candidates?.[0];
      if (candidate?.content?.parts) {
        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            const base64Res = part.inlineData.data;
            const enhancedDataUrl = `data:${part.inlineData.mimeType};base64,${base64Res}`;
            const res = await fetch(enhancedDataUrl);
            const blob = await res.blob();

            setEnhancedBlob(blob);
            setEnhancedUrl(enhancedDataUrl);
            setIsDone(true);
            foundImage = true;
            break;
          }
        }
      }

      if (!foundImage) throw new Error("The AI didn't return an image.");
    } catch (err: any) {
      console.error('Enhancement failed:', err);
