          <p className="text-2xl text-slate-700 dark:text-slate-200 font-black mb-2">Enhance to 4K Ultra-HD</p>
          <p className="text-slate-400 text-sm font-medium">Free AI Detail Reconstruction & Restoration</p>
        </div>
      ) : (
