              </label>
              <span className="text-sm font-black text-amber-600 bg-amber-50 dark:bg-amber-900/30 px-4 py-1.5 rounded-xl border border-amber-100 dark:border-amber-900/30 shadow-sm">{intensity}%</span>
            </div>
            <input 
