import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { GoogleGenAI } from "@google/genai";

const ImageEnhancer: React.FC = () => {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [enhancedUrl, setEnhancedUrl] = useState<string | null>(null);
  const [enhancedBlob, setEnhancedBlob] = useState<Blob | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [intensity, setIntensity] = useState(75);
  const [isDone, setIsDone] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [error, setError] = useState<React.ReactNode | null>(null);
  const [isKeySelected, setIsKeySelected] = useState<boolean | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setIsLoggedIn(!!session);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setIsLoggedIn(!!session);
    });

    // Proactively check for key selection as required for Gemini 3 Pro
    const checkKey = async () => {
      if (window.aistudio) {
        const has = await window.aistudio.hasSelectedApiKey();
        setIsKeySelected(has || !!process.env.API_KEY);
      } else {
        setIsKeySelected(!!process.env.API_KEY);
      }
    };
    checkKey();

    return () => subscription.unsubscribe();
  }, []);

  const fileToBase64 = (file: File | Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  const getClosestAspectRatio = (width: number, height: number): "1:1" | "4:3" | "3:4" | "16:9" | "9:16" => {
    const ratio = width / height;
    if (ratio > 1.5) return "16:9";
    if (ratio > 1.2) return "4:3";
    if (ratio < 0.6) return "9:16";
    if (ratio < 0.8) return "3:4";
    return "1:1";
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setEnhancedUrl(null);
      setEnhancedBlob(null);
      setIsDone(false);
      setIsSaved(false);
      setError(null);
    }
  };

  const handleOpenKeyDialog = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setIsKeySelected(true); // Proceed as per race condition guidelines
      setError(null);
    }
  };

  const handleEnhance = async () => {
    if (!selectedFile) return;

    if (!process.env.API_KEY && !window.aistudio) {
      setError(
        <div className="text-center py-4">
          <p className="font-bold text-red-600 mb-2">API Key Required</p>
          <p className="text-xs text-slate-500 mb-4">4K Restoration requires an authorized project key. Please add API_KEY to Vercel settings.</p>
          <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-[10px] text-primary-500 underline">Billing & Setup Guide</a>
        </div>
      );
      return;
    }

    setIsProcessing(true);
    setError(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const img = new Image();
      img.src = previewUrl!;
      await new Promise(r => img.onload = r);

      const targetAspectRatio = getClosestAspectRatio(img.width, img.height);
      const base64Data = await fileToBase64(selectedFile);

      const prompt = `Task: Perform an Ultra-HD 4K Image Restoration. Enhance details, remove noise, and reconstruct textures. Quality target: ${intensity}%. Output should be high fidelity.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: selectedFile.type } },
            { text: prompt }
          ]
        },
        config: {
          imageConfig: { 
            aspectRatio: targetAspectRatio,
            imageSize: '4K' 
          }
        }
      });

      let foundImage = false;
      const candidate = response.candidates?.[0];
      if (candidate?.content?.parts) {
        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            const base64Res = part.inlineData.data;
            const enhancedDataUrl = `data:${part.inlineData.mimeType};base64,${base64Res}`;
            const res = await fetch(enhancedDataUrl);
            const blob = await res.blob();

            setEnhancedBlob(blob);
            setEnhancedUrl(enhancedDataUrl);
            setIsDone(true);
            foundImage = true;
            break;
          }
        }
      }

      if (!foundImage) throw new Error("AI Restoration failed: Image output part missing.");
    } catch (err: any) {
      console.error('Enhancement failed:', err);
      const msg = err.message || "";
      if (msg.includes("Requested entity was not found") || msg.includes("API Key") || msg.includes("403")) {
        setIsKeySelected(false);
