            <img src={resultUrl || previewUrl!} className={`max-w-full max-h-full object-contain p-4 transition-all duration-1000 ${isProcessing ? 'scale-95 blur-sm opacity-50' : 'scale-100'}`} alt="Preview" />

            {!isProcessing && (
              <button onClick={clear} className="absolute top-4 right-4 z-40 w-12 h-12 bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm rounded-2xl flex items-center justify-center text-red-500 shadow-2xl border border-slate-100 dark:border-slate-700 hover:scale-110 transition-transform">
                <i className="fa-solid fa-trash-can"></i>
              </button>
            )}
          </div>

          {!isDone && !isProcessing && (
            <>
              {hasKey === false && window.aistudio ? (
                <div className="p-10 bg-indigo-50 dark:bg-indigo-900/10 rounded-[40px] border border-indigo-100 dark:border-indigo-900/30 text-center animate-in zoom-in-95">
                  <div className="w-16 h-16 bg-white dark:bg-slate-800 rounded-2xl flex items-center justify-center mx-auto mb-6 text-indigo-500 shadow-lg border border-indigo-50 dark:border-indigo-700">
                    <i className="fa-solid fa-key text-xl"></i>
                  </div>
                  <h4 className="text-xl font-black text-slate-800 dark:text-white mb-2">Connect to Google AI Studio</h4>
                  <p className="text-sm text-slate-500 dark:text-slate-400 mb-8 max-w-sm mx-auto">To enable AI background removal, please select your project API key from the dialog.</p>
                  <button 
