      console.error('Enhancement failed:', err);
      const msg = err.message || "";
      const isAuthError = msg.toLowerCase().includes("permission denied") || 
                          msg.toLowerCase().includes("api key") || 
                          msg.toLowerCase().includes("requested entity was not found") ||
                          msg.toLowerCase().includes("403");

      if (isAuthError) {
        setError(
          <div className="text-center py-4 space-y-4">
            <p className="font-black text-red-600 uppercase tracking-tight">Access Restricted</p>
            <p className="text-[11px] leading-relaxed text-slate-600">
              {qualityMode === 'ultra' 
                ? "The 'Ultra 4K' model requires a Google Cloud project with a Paid/Billing account. Please switch to 'Standard HD' or select a different project key."
                : "The API call was blocked. Please ensure your project is properly configured or connect a project key."}
            </p>
            {window.aistudio && (
              <button 
                onClick={async () => {
                  await window.aistudio?.openSelectKey();
                  handleEnhance();
                }} 
                className="px-8 py-3 bg-slate-800 text-white rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl"
              >
                Reconnect Project Key
              </button>
            )}
            {qualityMode === 'ultra' && (
              <button 
                onClick={() => {
                  setQualityMode('standard');
                  setError(null);
                }}
                className="block mx-auto text-[10px] text-indigo-500 font-bold underline"
              >
                Switch back to Standard HD
              </button>
            )}
          </div>
        );
      } else {
        setError(`AI Restoration failed: ${msg || "Try a different image format (JPG/PNG)."}`);
      }
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSaveToLibrary = async () => {
    const dataToSave = enhancedBlob || selectedFile;
    if (!dataToSave || !selectedFile) return;
    setIsSaving(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.user) throw new Error("Please log in to save.");

      const fileName = `${Date.now()}_enhanced_${selectedFile.name}`;
      const filePath = `${session.user.id}/${fileName}`;

      await supabase.storage.from('images').upload(filePath, dataToSave);
      const { data: { publicUrl } } = supabase.storage.from('images').getPublicUrl(filePath);

      await supabase.from('images').insert([{
        user_id: session.user.id,
        name: selectedFile.name,
        url: publicUrl,
        type: 'enhanced',
        date: new Date().toISOString(),
        size: qualityMode === 'ultra' ? '4K Ultra HD' : 'HD Enhanced'
      }]);

      setIsSaved(true);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSaving(false);
    }
  };

  const clear = () => {
    setSelectedFile(null);
    setPreviewUrl(null);
    setEnhancedUrl(null);
    setEnhancedBlob(null);
    setIsDone(false);
    setIsSaved(false);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="w-full max-w-2xl mx-auto bg-white dark:bg-slate-800 rounded-[40px] shadow-2xl p-8 border border-slate-100 dark:border-slate-700 transition-all">
