        <h3 className="text-xl font-black text-slate-800 dark:text-white flex items-center">
          <div className="w-10 h-10 bg-amber-100 dark:bg-amber-900/30 rounded-2xl flex items-center justify-center mr-4 text-amber-600">
             <i className="fa-solid fa-wand-magic-sparkles text-lg"></i>
          </div>
          Lama AI Image Enhancer
        </h3>
        <div className="flex items-center space-x-2">
           <span className={`text-[9px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full border ${qualityMode === 'ultra' ? 'text-primary-500 bg-primary-50 dark:bg-primary-900/30 border-primary-100' : 'text-slate-500 bg-slate-50 dark:bg-slate-900/30 border-slate-100'}`}>
             <i className={`fa-solid ${qualityMode === 'ultra' ? 'fa-bolt-lightning' : 'fa-sparkles'} mr-1`}></i> 
             {qualityMode === 'ultra' ? 'Ultra 4K Mode' : 'Standard HD'}
           </span>
        </div>
      </div>

      {!selectedFile ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-[32px] p-20 text-center cursor-pointer hover:border-amber-400 hover:bg-amber-50/30 dark:hover:bg-amber-900/10 transition-all group relative overflow-hidden"
        >
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
          <div className="absolute inset-0 bg-gradient-to-br from-amber-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>

          <div className="w-24 h-24 bg-amber-50 dark:bg-amber-900/20 rounded-[32px] flex items-center justify-center mx-auto mb-8 group-hover:scale-110 transition-transform duration-500 shadow-sm">
            <i className="fa-solid fa-image-portrait text-amber-500 text-4xl"></i>
          </div>
          <p className="text-2xl text-slate-700 dark:text-slate-200 font-black mb-2">Enhance to HD or 4K</p>
          <p className="text-slate-400 text-sm font-medium">AI detail restoration & pixel upscaling</p>
        </div>
      ) : (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          {error && (
            <div className="p-6 bg-red-50 dark:bg-red-900/10 border border-red-100 dark:border-red-900/30 rounded-[32px] text-slate-800 dark:text-slate-200 shadow-sm animate-in zoom-in-95">
              {error}
            </div>
          )}

          <div className="relative group rounded-[32px] overflow-hidden bg-slate-50 dark:bg-slate-900 border border-slate-100 dark:border-slate-700 aspect-video flex items-center justify-center shadow-inner">
            {isProcessing && (
               <div className="absolute inset-0 flex flex-col items-center justify-center z-30 bg-white/70 dark:bg-slate-900/70 backdrop-blur-md">
                  <div className="relative">
                    <div className="w-20 h-20 border-4 border-amber-500/10 border-t-amber-500 rounded-full animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                      <i className="fa-solid fa-microchip text-amber-500 animate-pulse"></i>
                    </div>
                  </div>
                  <p className="text-[10px] font-black text-amber-600 uppercase tracking-[0.2em] mt-6 animate-pulse">Reconstructing Pixels...</p>
               </div>
            )}
            <img src={enhancedUrl || previewUrl!} className={`max-w-full max-h-full object-contain p-4 transition-all duration-1000 ${isProcessing ? 'scale-95 blur-sm opacity-50' : 'scale-100'}`} alt="Preview" />

            {!isProcessing && (
              <button onClick={clear} className="absolute top-4 right-4 z-40 w-12 h-12 bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm rounded-2xl flex items-center justify-center text-red-500 shadow-2xl border border-slate-100 dark:border-slate-700 hover:scale-110 transition-transform">
                <i className="fa-solid fa-trash-can"></i>
              </button>
            )}
          </div>

          <div className="bg-slate-50 dark:bg-slate-900/30 p-6 rounded-[32px] border border-slate-100 dark:border-slate-800">
            <div className="flex flex-col sm:flex-row gap-4">
              <button 
                onClick={() => {
                  setQualityMode('standard');
                  setIsDone(false);
                  setEnhancedUrl(null);
                  setError(null);
                }}
                className={`flex-1 p-4 rounded-2xl border transition-all flex flex-col items-center text-center ${qualityMode === 'standard' ? 'bg-white dark:bg-slate-700 border-amber-500 shadow-lg' : 'bg-transparent border-slate-200 dark:border-slate-700 opacity-60'}`}
              >
                <i className="fa-solid fa-sparkles text-amber-500 mb-2"></i>
                <span className="text-xs font-black uppercase tracking-widest text-slate-700 dark:text-slate-200">Standard HD</span>
                <span className="text-[9px] text-slate-400 mt-1 uppercase">Reliable & Fast</span>
              </button>

              <button 
                onClick={() => {
                  setQualityMode('ultra');
                  setIsDone(false);
                  setEnhancedUrl(null);
                  setError(null);
                }}
                className={`flex-1 p-4 rounded-2xl border transition-all flex flex-col items-center text-center ${qualityMode === 'ultra' ? 'bg-white dark:bg-slate-700 border-primary-500 shadow-lg' : 'bg-transparent border-slate-200 dark:border-slate-700 opacity-60'}`}
              >
                <i className="fa-solid fa-bolt-lightning text-primary-500 mb-2"></i>
                <span className="text-xs font-black uppercase tracking-widest text-slate-700 dark:text-slate-200">Ultra 4K Mode</span>
                <span className="text-[9px] text-slate-400 mt-1 uppercase">Pro Project Required</span>
              </button>
            </div>
          </div>

          {!isDone && !isProcessing && (
            <button 
              onClick={handleEnhance} 
              className={`group w-full text-white font-black py-6 rounded-[32px] shadow-2xl transition-all hover:scale-[1.02] relative overflow-hidden ${qualityMode === 'ultra' ? 'bg-gradient-to-r from-primary-600 to-indigo-600 shadow-primary-500/30' : 'bg-gradient-to-r from-amber-500 to-orange-500 shadow-amber-500/30'}`}
            >
               <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-700"></div>
               <div className="flex items-center justify-center space-x-4">
                 <i className={`fa-solid ${qualityMode === 'ultra' ? 'fa-bolt-lightning' : 'fa-wand-magic-sparkles'} text-lg group-hover:rotate-12 transition-transform`}></i> 
                 <span className="text-lg">Run {qualityMode === 'ultra' ? '4K' : 'HD'} AI Enhancement</span>
               </div>
            </button>
          )}

          {isDone && (
            <div className="bg-green-50 dark:bg-green-900/10 border border-green-100 dark:border-green-900/30 rounded-[48px] p-10 animate-in zoom-in-95 duration-500">
              <div className="flex items-center justify-between mb-10 text-green-700 dark:text-green-400 font-black text-2xl">
                <div className="flex items-center">
                  <div className="w-14 h-14 bg-green-500 rounded-2xl flex items-center justify-center text-white mr-5 shadow-2xl shadow-green-500/20">
                    <i className="fa-solid fa-check text-xl"></i>
                  </div>
                  {qualityMode === 'ultra' ? '4K Master Ready' : 'HD Restored'}
                </div>
              </div>

              <div className="flex flex-col gap-5">
                <div className="flex gap-4">
                  <button onClick={clear} className="px-8 py-6 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-400 font-black rounded-[28px] border border-slate-200 dark:border-slate-700 hover:bg-slate-50 transition-all hover:scale-105 shadow-sm">
                    <i className="fa-solid fa-rotate-left"></i>
                  </button>
                  <a 
                    href={enhancedUrl!} 
                    download={`LamaEnhanced_${selectedFile.name}`} 
                    className="flex-grow text-center bg-primary-600 text-white font-black py-6 rounded-[28px] shadow-2xl shadow-primary-500/30 hover:scale-[1.02] hover:bg-primary-700 transition-all flex items-center justify-center space-x-3 text-lg"
                  >
                    <i className="fa-solid fa-download"></i>
                    <span>Download {qualityMode === 'ultra' ? '4K' : 'HD'} Image</span>
                  </a>
                </div>
                {isLoggedIn && (
                  <button 
                    onClick={handleSaveToLibrary} 
                    disabled={isSaved || isSaving} 
                    className={`w-full py-5 rounded-[24px] font-black text-sm transition-all flex items-center justify-center space-x-2 ${isSaved ? 'bg-green-100 text-green-600 border border-green-200' : 'bg-slate-800 dark:bg-slate-700 text-white hover:bg-black shadow-xl'}`}
                  >
                    {isSaving ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className={`fa-solid ${isSaved ? 'fa-check' : 'fa-cloud-arrow-up'}`}></i>}
                    <span>{isSaved ? 'Restoration Saved to Cloud' : isSaving ? 'Uploading Assets...' : 'Save to My Library'}</span>
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

