      const config: any = {};
      if (qualityMode === 'ultra') {
        config.imageConfig = { 
          aspectRatio: targetAspectRatio,
          imageSize: '4K' 
        };
      }

      const response = await ai.models.generateContent({
        model: modelName,
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: selectedFile.type } },
            { text: prompt }
          ]
        },
        config: config
