    fetchApprovedReviews();

    const channel = supabase
      .channel('public:reviews')
      .on('postgres_changes', 
        { event: '*', schema: 'public', table: 'reviews' }, 
        (payload) => {
          fetchApprovedReviews();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
